/* src/index.css */
@import url('https://fonts.googleapis.com/css2?family=Jakarta+Sans:wght@400;600;800&display=swap');

:root {
  --bg-0: #08090d;
  --bg-1: #111318;
  --bg-2: #191c24;
  --bg-3: #21252f;
  --text-primary: #e2e8f0;
  --text-muted: #94a3b8;
  --border-color: #333741;
  --accent: #6366f1;
  --danger: #ef4444;
  --success: #16a34a;
  --warning: #f59e0b;

/* Typography */
body {
  font-family: 'Jakarta Sans', sans-serif;
  background-color: var(--bg-0);
  color: var(--text-primary);
  min-height: 100vh;
  display: flex;
  justify-content: center;
  align-items: center;
  margin: 0;
  padding: 0;
}

/* Layout */
.container {
  width: 100%;
  max-width: 6xl;
  padding: var(--spacing-lg);
}

/* Spacing */
.gap-2 {
  margin-top: var(--spacing-md);
  margin-bottom: var(--spacing-lg);
}

.mt-4 {
  margin-top: var(--spacing-lg);
}

.mb-6 {
  margin-bottom: var(--spacing-xl);
}

/* Typography */
h1 {
  font-weight: 800;
  font-size: var(--text-2xl);
  line-height: 1.2;
  margin-bottom: var(--spacing-lg);
}

p {
  color: var(--text-muted);
  line-height: 1.6;
}

.text-sm {
  font-size: var(--text-sm);
}

.text-base {
  font-size: var(--text-base);
}

.text-lg {
  font-size: var(--text-lg);
}

.text-xl {
  font-size: var(--text-xl);
}

.text-2xl {
  font-size: var(--text-2xl);
}

.text-bold {
  font-weight: 700;
}

.text-sm {
  font-size: var(--text-sm);
}

.text-xs {
  font-size: var(--text-xs);
}

.text-muted {
  color: var(--text-muted);
}

.text-dim {
  font-weight: 400;
}

.text-accent {
  color: var(--accent);
}

.text-danger {
  color: var(--danger);
}

.text-success {
  color: var(--success);
}

/* Cards */
.card {
  background-color: var(--bg-1);
  border: 1px solid var(--border-color);
  border-radius: var(--radius-lg);
  padding: var(--spacing-xl);
  box-shadow: var(--shadow-md);
}

.card.glass {
  background-color: rgba(17, 19, 24, 0.8); /* Subtle glass effect */
  backdrop-filter: blur(10px);
}

.card.glow {
  border: 1px solid var(--accent);
  box-shadow: 0 0 20px rgba(99, 102, 241, 0.3);
}

/* Progress Bar */
.progress-container {
  height: var(--spacing-md);
  background-color: var(--bg-2);
  border-radius: var(--radius-lg);
  overflow: hidden;
  margin-top: var(--spacing-lg);
}

.progress-bar {
  height: 100%;
  background: linear-gradient(to right, var(--accent), #333741);
  transition: width var(--duration-normal);
}

.progress-text {
  font-weight: 600;
  text-align: center;
  margin-top: var(--spacing-sm);
  font-size: var(--text-lg);
}

/* Timer Display */
.timer-display {
  font-size: var(--text-2xl);
  font-weight: 800;
  letter-spacing: 0.05em;
  margin-bottom: var(--spacing-md);
  color: var(--accent);
}

.timer-segment {
  height: var(--spacing-lg);
  display: flex;
  align-items: center;
  justify-content: center;
  margin-bottom: var(--spacing-sm);
}

.time-value {
  font-size: var(--text-xl);
  font-weight: 800;
  color: var(--accent);
}

.timer-bg {
  background-color: var(--bg-3);
}

/* Controls */
.controls {
  display: flex;
  justify-content: center;
  gap: var(--spacing-md);
  margin-top: var(--spacing-xl);
}

.timer-btn {
  width: 100%;
  height: var(--size-md);
  border-radius: var(--radius-lg);
  font-size: var(--text-lg);
  font-weight: 600;
  transition: all var(--duration-fast);
}

.timer-btn:hover {
  transform: translateY(-1px);
  box-shadow: 0 4px 12px rgba(99, 102, 241, 0.3);
}

.timer-btn.active {
  background: linear-gradient(to right, var(--accent), #6366f1);
  box-shadow: 0 0 15px rgba(99, 102, 241, 0.5);
}

.timer-btn.danger {
  background-color: var(--danger);
  box-shadow: 0 0 15px rgba(239, 68, 68, 0.5);
}

/* Notification */
.toast {
  position: fixed;
  bottom: var(--spacing-xl);
  right: var(--spacing-lg);
  z-index: 1000;
  padding: var(--spacing-sm) var(--spacing-md);
  border-radius: var(--radius-lg);
  background-color: var(--bg-3);
  border: 1px solid var(--border-color);
  box-shadow: var(--shadow-lg);
  opacity: 0;
  transform: scale(0.95);
  pointer-events: none;
  transition: opacity var(--duration-fast), transform var(--animation-ease);
}

.toast.show {
  opacity: 1;
  transform: scale(1);
}

.toast-icon {
  width: var(--size-sm);
  height: var(--size-sm);
  border-radius: var(--radius-lg);
  display: flex;
  align-items: center;
  justify-content: center;
  margin-right: var(--spacing-sm);
}

.toast-text {
  font-size: var(--text-base);
  font-weight: 600;
}

.toast-close {
  cursor: pointer;
  color: var(--text-muted);
  margin-left: var(--spacing-sm);
}

import { useState, useEffect } from "react";
import { Clock, Pause, Play, Zap, Loader, X } from "lucide-react";
import { Time } from "lucide-react";

const App = () => {
  const [isRunning, setIsRunning] = useState(false);
  const [timeLeft, setTime] = useState(25 * 60); // Start with 25 minutes
  const [mode, setMode] = useState("work"); // "work", "break", "rest"
  const [intervalId, setIntervalId] = useState<number | null>(null);

  const formatTime = (seconds: number) => {
    const h = Math.floor(seconds / 3600);
    const m = Math.floor((seconds % 3600) / 60);
    const s = Math.floor(seconds % 60);
    return `${h.toString().padStart(2, '0')}:${m.toString().padStart(2, '0')}:${s.toString().padStart(2, '0")}`;
  };

  const handleTimerChange = (amount: number) => {
    if (isRunning) {
      if (timeLeft > 0) {
        setTime((prev) => Math.max(0, prev - amount));
      } else {
        handleModeSwitch();
      }
    } else {
      // Start timer
      setIntervalId(1000 * 60); // 1 minute for testing
      setIsRunning(true);
    }
  };

  const handleStartPause = () => {
    if (isRunning) {
      clearInterval(intervalId);
      setIsRunning(false);
    } else {
      // Start timer
      setIntervalId(1000 * 60); // 1 minute for testing
      setIsRunning(true);
    }
  };

  const handleReset = () => {
    clearInterval(intervalId);
    setTime(25 * 60); // Reset to 25 minutes
    setMode("work");
    setIsRunning(false);
  };

  const handleModeSwitch = () => {
    if (mode === "work") {
      setMode("break");
    } else if (mode === "break") {
      setMode("rest");
    } else {
      setMode("end");
    }
  };

  const formatTimeDisplay = (totalSeconds: number) => {
    const h = Math.floor(totalSeconds / 3600);
    const m = Math.floor((totalSeconds % 3600) / 60);
    const s = Math.floor(totalSeconds % 60);
    return `${h.toString().padStart(2, '0')}:${m.toString().padStart(2, '0')}:${s.toString().padStart(2, '0")}`;
  };

  const handleEndSession = () => {
    clearInterval(intervalId);
    setIsRunning(false);
    setMode("done");
  };

  const handleStartTimer = () => {
    if (mode === "work") {
      setTime(25 * 60); // Start with 25 minutes
      setIsRunning(true);
    } else if (mode === "break") {
      setTime(15 * 60); // Start with 15 minutes
      setIsRunning(true);
    } else if (mode === "end") {
      handleEndSession();
    }
  };

  const handleSwitchMode = () => {
    if (mode === "work") {
      setMode("break");
    } else if (mode === "rest") {
      setMode("end");
    } else {
      handleEndSession();
    }
  };

  const TimeSegment = ({ label, time, isRunning }: { label: string, time: number, isRunning: boolean }) => {
    const isFinished = time === 0;
    const color = isFinished ? "text-muted" : isRunning ? "text-accent" : "text-dim";

    return (
      <div className={`flex flex-col items-center space-y-2 ${isFinished ? 'opacity-50' : 'animate-pulse'}`}>
        <p className={`text-sm font-semibold ${color}`}>{label}</p>
        <div className="flex items-center justify-center gap-2">
          <Time className={`w-full h-full ${isRunning ? 'text-accent' : 'text-muted'}`} className="text-xl font-extrabold transition duration-300 ease-in-out`}>{formatTime(time)}</div>
        <div className="w-full h-1 bg-gray-700 rounded-full relative">
          <div className={`absolute top-0 left-0 h-full w-full rounded-full ${isFinished ? 'bg-red-500' : isRunning ? 'bg-accent animate-pulse' : 'bg-gray-600'}`} style={{ width: `${(time / 60).toFixed(1)}` }}></div>
        </div>
      </div>
    );
  };

  const TimeSegment = ({ label, time, isRunning }: { label: string, isFinished: boolean, isWorking: boolean }) => {
    const color = isFinished ? "text-muted" : isWorking ? "text-accent" : "text-dim";

    return (
      <div className={`flex flex-col items-center space-y-2 ${isFinished ? 'opacity-50' : isWorking ? 'animate-pulse' : 'text-dim'}`}>
        <p className={`text-sm font-semibold ${color}`}>{label}</p>
        <div className="flex items-center justify-center gap-2">
          <Time className={`w-full h-full ${isFinished ? 'text-red-500' : isRunning ? 'text-accent' : 'text-muted'}`} className="text-xl font-extrabold transition duration-300 ease-in-out`}>{formatTime(time)}</div>
        <div className="w-full h-1 bg-gray-700 rounded-full relative">
          <div className={`absolute top-0 left-0 h-full w-full rounded-full ${isFinished ? 'bg-red-500' : isRunning ? 'bg-accent animate-pulse' : 'bg-gray-600'}`} style={{ width: `${(time / 60).toFixed(1)}` }}></div>
        </div>
      </div>
    );
  };

  return (
    <div className="container min-h-screen flex flex-col items-center justify-center p-4">
      <div className="card glass p-6 max-w-xl w-full text-center">
        <h1 className="text-3xl font-bold mb-2">Pomodoro Timer</h1>
        <div className="flex justify-center gap-4 mb-6">
          <Time className={`w-full h-full ${isRunning ? 'text-red-500 animate-spin' : 'text-muted'}`} className="text-3xl font-extrabold transition duration-300 ease-in-out`}>{formatTime(timeLeft)}</div>
          <button
            className={`w-1/2 p-4 rounded-lg text-lg font-semibold transition duration-300 ease-in-out ${isRunning ? 'bg-red-600 shadow-lg hover:shadow-xl' : 'bg-gray-800 hover:bg-gray-700 border border-gray-700 hover:border-accent'}`}
            onClick={handleStartPause}
          >
            {isRunning ? <Pause className="w-6 h-6 animate-spin" /> : <Play className="w-6 h-6 animate-bounce" />}
          </button>
          <button
            className={`w-1/2 p-4 rounded-lg text-base font-semibold transition duration-300 ease-out-expo ${isFinished ? 'bg-red-600 shadow-xl hover:shadow-2xl' : 'bg-gray-800 hover:bg-gray-700 border border-gray-700 hover:border-accent'}`}
            onClick={handleReset}
          >
            {mode === "work" ? <Clock className="w-6 h-6 animate-pulse" /> : <Zap className="w-6 h-6 animate-bounce" />}
          </button>
        </div>

        <div className="flex justify-center gap-4 mt-6">
          <TimeSegment label="Work" time={formatTime(timeLeft)} isRunning={isRunning} />
          <TimeSegment label="Break" time={formatTime(breakTime)} isFinished={isBreakFinished} />
          <TimeSegment label="Rest" time={formatTime(restTime)} isFinished={isRestFinished} />
        </div>

        {isFinished && (
          <div className={`mt-8 p-4 rounded-lg ${mode === "done" ? 'bg-success/10 border border-success' : 'bg-gray-800 border border-gray-700'}`}>
            <p className={`text-base font-bold ${mode === "end" ? 'text-xl text-white' : 'text-sm text-muted'}`}>
              {mode === "work" && "Session Complete!"}
              {mode === "break" && "Time to stretch!"}
              {mode === "rest" && "Relax and recharge!"}
            </p>
            <button
              className={`mt-4 px-4 py-2 text-sm font-semibold rounded-lg transition duration-300 ${mode === "restart" ? 'bg-accent text-white hover:bg-accent/90 shadow-lg' : 'bg-gray-800 text-muted hover:bg-gray-700 border border-gray-700 hover:border-accent'}`}
              onClick={handleRestart}
            >
              {mode === "restart" ? <Clock className="w-5 h-5 animate-spin" /> : <X className="w-5 h-5 animate-rotate-slow" />}
            </button>
          </div>
        )}
      </div>
      <div className="toast fixed bottom-6 right-6 flex items-center justify-end gap-2">
        {isFinished && (
          <div className={`flex items-center space-x-2 ${mode === "done" ? 'text-success' : 'text-muted'}`}>
            <Zap className="w-5 h-5 text-red-500 animate-pulse" />
            <p className="text-sm font-medium">{mode}</p>
            <button
              className={`px-3 py-1 text-xs font-semibold rounded-lg transition duration-300 ${mode === "next" ? 'bg-accent text-white hover:bg-accent/90 shadow-lg' : 'bg-gray-800 text-muted hover:bg-gray-700 border border-gray-700 hover:border-accent'}`}
              onClick={handleEndSession}
            >
              {mode === "next" ? <Clock className="w-5 h-5 animate-rotate-slow" /> : <X className="w-5 h-5 text-red-500 animate-fade-out" />}
            </button>
          </div>
        )}
      </div>
    </div>
  );
};

export default App;
